下面是一个示例代码，它演示了如何在驱动中使用 dma_set_mask_and_coherent 函数：

```
static int my_device_probe(struct platform_device *pdev)
{
    struct my_device *dev;
    struct resource *res;

    dev = devm_kzalloc(&pdev->dev, sizeof(*dev), GFP_KERNEL);
    if (!dev)
        return -ENOMEM;

    res = platform_get_resource(pdev, IORESOURCE_MEM, 0);
    if (!res)
        return -ENODEV;

    dev->regs = devm_ioremap_resource(&pdev->dev, res);
    if (IS_ERR(dev->regs))
        return PTR_ERR(dev->regs);

    /* Set device DMA mask and coherence properties */
    if (dma_set_mask_and_coherent(&pdev->dev, DMA_BIT_MASK(32)) != 0) {
        dev_err(&pdev->dev, "Failed to set DMA mask\n");
        return -EINVAL;
    }

    /* ... Other initialization code here ... */

    return 0;
}

static struct platform_driver my_device_driver = {
    .probe      = my_device_probe,
    .driver     = {
        .name   = "my_device",
        .owner  = THIS_MODULE,
    },
};
```

在上面的示例代码中，`my_device_probe` 函数是设备驱动的初始化函数，它在执行其他初始化代码之前调用 `dma_set_mask_and_coherent` 函数来设置 DMA 属性。若设置 DMA 属性成功，则返回 0。之后， `my_device_probe` 函数将继续执行其他初始化代码。

"dma_alloc_coherent" 是 Linux 内核中的一个函数，用于在内核中为DMA（直接内存存取）操作分配一块内存区域，保证所分配的内存区域能够对齐到硬件的 DMA 地址和大小要求。

为了避免数据传输时的额外内存拷贝，应用程序通常将数据直接传入到硬件设备的缓冲区中，以此来提高传输速度，这就需要使用 DMA（直接内存存取）技术来实现。因此，DMA缓冲区的管理成为了驱动程序中一个很重要的任务。在进行 DMA 缓冲区管理时，往往需要使用到 "dma_alloc_coherent" 函数。

具体来说，"dma_alloc_coherent" 函数可以分配一块用户可访问的、 DMA 可直接访问的大块内存区域。在分配 DMA 缓存区之前，设备的 DMA属性必须根据设备的硬件平台进行配置，然后使用该函数来分配缓存区。dma_alloc_coherent可以保证从内存中分配的缓存区的地址及大小满足设备的DMA要求，并且避免了因不对齐而产生额外内存拷贝的开销。

调用 dma_alloc_coherent 时，需要指定设备的 struct device 对象， 分配内存的大小（以字节为单位）和用于对齐缓存区的参考内存地址。分配完成后， dma_alloc_coherent 函数将返回一个指向分配内存区域的指针。

下面是一个示例代码，该示例代码演示了如何在驱动程序中分配 DMA 缓存区，假定已经进行DMA属性的设置：

```
void *buffer;
dma_addr_t dma_handle;
size_t size = 4096;

buffer = dma_alloc_coherent(&my_device->dev, size, &dma_handle, GFP_KERNEL);

if (!buffer) {
    /* Handle allocation failure */
}

/* Use DMA buffer here... */
```

在上面的代码中，`dma_alloc_coherent` 函数被使用来从内核堆中分配 4KB 的内存区域，该内存区域可以用于DMA操作，并使用 dma_handle 指针来获取物理地址。如果内存分配失败，该函数将返回 NULL。

"shared-dma-pool" 是内核提供的一个 DMA 缓存池，可以将多个设备的 DMA 缓存区共享在一起，从而节省内存使用。对于一些设备，如果需要分配大量的 DMA 缓存空间，使用 shared-dma-pool 宏可以提高内存分配效率和性能。

在使用 shared-dma-pool 宏分配 DMA 缓存区之前，需要先在驱动的设备探测函数中初始化共享池。通常使用 `dma_declare_coherent_memory` 函数进行初始化，该函数需要指定需要共享的 DMA 缓存池的起始地址、空间大小、描述符等信息。

初始化后，在驱动代码中可以使用 shared-dma-pool 宏来分配 DMA 缓存，使用方法与 dma_alloc_coherent 函数基本相同，只是需要在第二个参数中传入代码中定义的 struct device 对象，而不是单个设备对象。

下面是一个示例代码，演示如何在设备探测函数中使用dma_declare_coherent_memory初始化 shared-dma-pool 并在设备驱动程序中使用 shared-dma-pool 宏来分配 DMA 缓存：

```
static int my_device_probe(struct platform_device *pdev)
{
    struct my_device *dev;
    struct resource *res;
    int ret;

    /* Initialize shared DMA pool */
    ret = dma_declare_coherent_memory(&pdev->dev, DMA_MEMORY_START, DMA_MEMORY_SIZE);
    if (ret) {
        dev_err(&pdev->dev, "Failed to declare coherent memory: %d\n", ret);
        return ret;
    }

    /* ... Other initialization code here ... */

    return 0;
}

static int my_device_open(struct inode *inode, struct file *file)
{
    struct my_device *dev = container_of(inode->i_cdev, struct my_device, cdev);
    file->private_data = dev;

    /* Use shared DMA pool to allocate DMA buffer */
    dev->dma_buffer = shared_dma_pool_alloc(&dev->dev, DMA_BUFFER_SIZE, &dev->dma_handle);
    if (!dev->dma_buffer) {
        dev_err(&dev->dev, "Failed to allocate DMA buffer\n");
        return -ENOMEM;
    }

    /* ... Other open code here ... */

    return 0;
}
```

在上面的代码中，在设备探测函数中使用 `dma_declare_coherent_memory` 函数初始化了一个共享 DMA 缓存池，然后在设备打开函数中使用 shared-dma-pool 宏来分配 DMA 缓存区和物理地址。

下面是一个示例代码，演示通过 `dma_declare_coherent_memory` 函数设置和使用共享 DMA 缓存池的过程：

```
#include <linux/types.h>
#include <linux/dma-mapping.h>

#define DMA_MEMORY_START   0x40000000
#define DMA_MEMORY_SIZE    (16 * 1024 * 1024)

static int my_driver_probe(struct platform_device *pdev)
{
    int ret;
    struct device *dev = &pdev->dev;
    dma_addr_t dma_handle;
    void *dma_buffer;

    /* Configure shared DMA pool */
    ret = dma_declare_coherent_memory(dev, DMA_MEMORY_START, DMA_MEMORY_SIZE);
    if (ret)
        return -EINVAL;

    /* Allocate DMA buffer from shared DMA pool */
    dma_buffer = shared_dma_pool_alloc(dev, 0x1000, &dma_handle);
    if (!dma_buffer)
        return -ENOMEM;

    /* Do something useful with DMA buffer... */

    /* Free DMA buffer and exit function */
    shared_dma_pool_free(dev, dma_buffer, 0x1000, dma_handle);

    return 0;
}

static const struct of_device_id my_driver_dt_match[] = {
    { .compatible = "my_driver", },
    { },
};
MODULE_DEVICE_TABLE(of, my_driver_dt_match);

static struct platform_driver my_driver = {
    .probe = my_driver_probe,
    .driver = {
        .name = "my_driver",
        .of_match_table = my_driver_dt_match,
    },
};

module_platform_driver(my_driver);
```

在上面的代码中，my_driver_probe 函数通过 `dma_declare_coherent_memory` 函数设置一个共享 DMA 缓存池。然后，使用 `shared_dma_pool_alloc` 函数从该共享 DMA 缓存池中分配了 0x1000 字节大小的 DMA 缓存区，并将分配到的物理地址存储在 dma_handle 变量中。在分配完成后，可以使用缓存区来进行有关 DMA 的操作。最后，使用 `shared_dma_pool_free` 函数来释放 DMA 缓存区。

在实际使用 shared-dma-pool 过程中，需要根据实际需要进行相关配置，并且需要注意 DMA 属性的正确设置，以确保分配到的 DMA 缓存区能够被硬件直接访问，并能满足传输要求。

通过 "reserved-memory" 保留的内存区域可以被 DMA（直接内存访问）调用。在驱动程序中，可以通过指向保留内存区域的指针作为参数来执行 DMA 操作，从而实现高速数据传输。

在系统启动时，Linux 内核会根据设备树中的描述，将 "reserved-memory" 中的内存区域分配给相应的设备。然后，在驱动程序中可以通过指向该内存区域的指针执行 DMA 操作。具体来说，可以使用 dma_map_single 或 dma_map_page 函数将保留内存区域映射为 DMA 可直接访问的内存区域，并返回对应的 DMA 物理地址。

下面是一个示例代码，演示了如何在驱动程序中使用 "reserved-memory" 保留的内存区域进行 DMA 操作：

```
#include <linux/platform_device.h>
#include <linux/dma-mapping.h>

static int my_device_probe(struct platform_device *pdev)
{
    struct resource *res;
    dma_addr_t dma_handle;
    void *buffer;
    int ret;

    /* Get reserved memory region */
    res = platform_get_resource(pdev, IORESOURCE_MEM, 0);
    if (!res) {
        dev_err(&pdev->dev, "Failed to get reserved memory resource\n");
        return -EINVAL;
    }

    /* Map reserved memory region to DMA buffer */
    buffer = devm_ioremap(&pdev->dev, res->start, resource_size(res));
    if (!buffer) {
        dev_err(&pdev->dev, "Failed to ioremap reserved memory\n");
        return -ENOMEM;
    }

    /* Map DMA buffer to physical address */
    dma_handle = dma_map_single(&pdev->dev, buffer, resource_size(res), DMA_FROM_DEVICE);
    if (dma_mapping_error(&pdev->dev, dma_handle)) {
        dev_err(&pdev->dev, "Failed to map DMA buffer\n");
        return -ENOMEM;
    }

    /* Use DMA buffer here... */

    /* Unmap DMA buffer */
    dma_unmap_single(&pdev->dev, dma_handle, resource_size(res), DMA_FROM_DEVICE);

    return 0;
}

static struct of_device_id my_device_of_match[] = {
    { .compatible = "example,my-device", },
    { },
};
MODULE_DEVICE_TABLE(of, my_device_of_match);

static struct platform_driver my_device_driver = {
    .driver = {
        .name = "my-device",
        .of_match_table = my_device_of_match,
    },
    .probe = my_device_probe,
};
```

在上面的代码中，通过 platform_get_resource 函数获取了设备树中 "reserved-memory" 对应的资源，然后使用 devm_ioremap 函数将该资源映射到内存中，并使用 dma_map_single 函数将映射后的内存区域映射为 DMA 可直接访问的内存区域。在操作完成后，使用 dma_unmap_single 函数将该 DMA 映射取消，并释放相关的资源。
